<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Url = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://victoriametrics:8428/api/v1/write&quot;</span></span>
